import publications from "./publications.json";

export default function Publications() {
  const filters = ["Artigos", "Anais de Eventos", "Capítulos de Livros", "Livros"];

  // Get first 10 publications ordered by year (descending)
  const recentPublications = [...publications]
    .sort((a, b) => Number(b.year) - Number(a.year))
    .slice(0, 5);

  return (
    <main className="flex-1 max-w-7xl mx-auto w-full px-6 md:px-20 py-12">
      <div className="mb-10">
        <h1 className="font-serif text-4xl mb-4 text-content-dark">Publicações</h1>
        <p className="text-content-muted text-lg max-w-3xl font-light leading-relaxed">
          Uma coleção selecionada de artigos, conferências e trabalhos técnicos que refletem minha pesquisa e contribuições para a comunidade acadêmica.
        </p>
      </div>

      {/* Search and Filters */}
      <div className="flex flex-col gap-6 mb-8">
        <div className="relative w-full">
          <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-content-muted">search</span>
          <input
            className="w-full bg-white border border-gray-200 rounded-2xl py-4 pl-12 pr-6 text-sm focus:ring-2 focus:ring-primary focus:border-transparent outline-none shadow-sm transition-all"
            placeholder="Pesquisar publicações..."
            type="text"
          />
        </div>
        <div className="flex flex-wrap gap-2 items-center">
          <span className="text-[10px] font-black uppercase tracking-widest text-content-muted mr-3">Filter:</span>
          {filters.map((filter, idx) => (
            <button
              key={filter}
              className={`px-4 py-1.5 rounded-full text-[11px] font-bold transition-all ${idx === 0
                  ? "bg-content-dark text-white shadow-sm"
                  : "bg-white text-content-muted border border-gray-200 hover:border-content-dark hover:text-content-dark"
                }`}
            >
              {filter}
            </button>
          ))}
        </div>
      </div>

      {/* Publications Table */}
      <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-sm">
        {/* Table Header */}
        <div className="grid grid-cols-[1fr_240px_100px_120px] items-center py-2 px-4 bg-gray-50 border-y border-gray-200 text-[10px] font-black uppercase tracking-widest text-content-muted">
          <div>Título e Autores</div>
          <div>Publicação</div>
          <div className="text-center">Ano</div>
          <div className="text-right"></div>
        </div>

        {/* Table Rows */}
        {recentPublications.map((pub) => (
          <div key={pub.title} className="group grid grid-cols-[1fr_240px_100px_120px] items-center py-3 px-4 border-b border-gray-100 bg-white hover:bg-blue-50/30 transition-colors">
            <div className="pr-6">
              <h3 className="font-serif text-base text-content-dark mb-1 group-hover:text-primary transition-colors">
                {pub.title}
              </h3>
              <p className="text-xs text-content-muted">
                {pub.authors.map((author, idx) => (
                  <span key={author}>
                    {author === "SIMÃO, J. P. S." ? (
                      <span className="font-bold text-gray-700">{author}</span>
                    ) : (
                      author
                    )}
                    {idx < pub.authors.length - 1 && ", "}
                  </span>
                ))}
              </p>
            </div>
            <div className="text-xs text-content-muted uppercase leading-tight pr-4">
              {pub.venue}
              {pub.volumeIssue && <span className="block text-[10px] text-gray-400 mt-0.5">{pub.volumeIssue}</span>}
            </div>
            <div className="text-center">
              <span className="text-xs font-bold text-primary bg-blue-50 px-2 py-1 rounded">{pub.year}</span>
            </div>
            <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              {pub.doi &&
                <button
                  className="p-1.5 hover:bg-gray-100 rounded-lg text-content-muted hover:text-primary transition-colors"
                  title="Ler"
                >
                  <span className="material-symbols-outlined text-lg">description</span>
                </button>
              }
              <button
                className="p-1.5 hover:bg-gray-100 rounded-lg text-content-muted hover:text-primary transition-colors"
                title="Cite"
              >
                <span className="material-symbols-outlined text-lg">format_quote</span>
              </button>
              <button
                className="p-1.5 hover:bg-gray-100 rounded-lg text-content-muted hover:text-primary transition-colors"
                title="BibTeX"
              >
                <span className="material-symbols-outlined text-lg">code</span>
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Load More */}
      <div className="mt-8 flex justify-center">
        <button className="text-xs font-black uppercase tracking-widest text-content-muted hover:text-primary transition-colors flex items-center gap-2">
          Load More Publications
          <span className="material-symbols-outlined text-sm">expand_more</span>
        </button>
      </div>
    </main>
  );
}
